 //! Shared utilities for RCH.

+fn find_value_end(s: &str) -> usize {
+    let mut chars = s.chars();
+    let mut end = 0;
+    let mut in_quote = None;
+    let mut escaped = false;
+
+    while let Some(c) = chars.next() {
+        let char_len = c.len_utf8();
+
+        if escaped {
+            escaped = false;
+            end += char_len;
+            continue;
+        }
+
+        if c == '\\' {
+            escaped = true;
+            end += char_len;
+            continue;
+        }
+
+        if let Some(q) = in_quote {
+            if c == q {
+                in_quote = None;
+            }
+            end += char_len;
+            continue;
+        }
+
+        if c == '"' || c == '\'' {
+            in_quote = Some(c);
+            end += char_len;
+            continue;
+        }
+
+        if c.is_whitespace() {
+            break;
+        }
+
+        end += char_len;
+    }
+    end
+}
